use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Database\Eloquent\Relations\HasOne;
use Illuminate\Database\Eloquent\SoftDeletes;
use Illuminate\Support\Str;

class Hunt extends Model
{
    use SoftDeletes;

    protected $fillable = [
        'user_id', 'title', 'location_name', 'latitude', 'longitude',
        'country', 'region', 'is_coastal', 'starts_at', 'ends_at',
        'notes', 'share_token', 'is_public',
    ];

    protected function casts(): array
    {
        return [
            'latitude' => 'decimal:7',
            'longitude' => 'decimal:7',
            'is_coastal' => 'boolean',
            'is_public' => 'boolean',
            'starts_at' => 'datetime',
            'ends_at' => 'datetime',
        ];
    }

