    public function __construct(
        private WeatherProviderInterface $weatherProvider,
        private TideProviderInterface $tideProvider,
        private SpeciesInfoProviderInterface $speciesProvider,
    ) {}

    public function generateBriefing(Hunt $hunt): HuntBriefing
    {
        $briefing = $hunt->briefing ?? new HuntBriefing(['hunt_id' => $hunt->id]);
        $briefing->status = 'generating';
        $briefing->save();

        try {
            $lat = $hunt->latitude ?? 51.5074;
            $lng = $hunt->longitude ?? -0.1278;
            $month = $hunt->starts_at->month;

            $cacheKey = "hunt_briefing_{$hunt->id}";

            $weatherData = Cache::remember(
                "weather_{$lat}_{$lng}_{$hunt->starts_at->format('Y-m-d')}",
                3600,
                fn() => $this->weatherProvider->getForecast($lat, $lng, $hunt->starts_at, $hunt->ends_at)
            );

            $tideData = null;
            if ($hunt->is_coastal) {
                $tideData = Cache::remember(
                    "tides_{$lat}_{$lng}_{$hunt->starts_at->format('Y-m-d')}",
                    3600,
                    fn() => $this->tideProvider->getTides($lat, $lng, $hunt->starts_at)
                );
            }

            $speciesData = Cache::remember(
                "species_{$lat}_{$lng}_{$month}_{$hunt->is_coastal}",
                86400,
                fn() => $this->speciesProvider->getSpeciesForLocation($lat, $lng, $month, $hunt->is_coastal)
            );

            $suggestions = $this->generateSuggestions($hunt, $weatherData, $tideData, $speciesData);

            DB::transaction(function () use ($briefing, $hunt, $weatherData, $tideData, $speciesData, $suggestions) {
                $briefing->update([
                    'weather_data' => $weatherData,
                    'tide_data' => $tideData,
                    'species_data' => $speciesData,
                    'suggestions' => $suggestions,
                    'weather_provider' => $this->weatherProvider->getProviderName(),
                    'tide_provider' => $hunt->is_coastal ? $this->tideProvider->getProviderName() : null,
                    'species_provider' => $this->speciesProvider->getProviderName(),
                    'status' => 'complete',
                    'error_message' => null,
                    'generated_at' => now(),
                    'expires_at' => now()->addHours(6),
                ]);

                $hunt->checklistItems()->delete();
                $this->generateChecklist($hunt, $weatherData, $tideData, $speciesData, $suggestions);
            });

            return $briefing->fresh();
        } catch (\Exception $e) {
            Log::error('Hunt briefing generation failed', [
                'hunt_id' => $hunt->id,
                'error' => $e->getMessage(),
            ]);

            $briefing->update([
                'status' => 'failed',
                'error_message' => $e->getMessage(),
            ]);

            return $briefing;
        }
    }

    private function generateSuggestions(Hunt $hunt, array $weather, ?array $tides, array $species): array
    {
        $suggestions = [];

        $sunrise = $weather['summary']['sunrise'] ?? '06:00';
        $sunset = $weather['summary']['sunset'] ?? '18:00';

        $suggestions['best_times'] = [];
        $suggestions['best_times'][] = "🌅 Dawn bite: Arrive by {$sunrise} for the best morning action.";

        if ($tides && !empty($tides['tides'])) {
            foreach ($tides['tides'] as $tide) {
                if ($tide['type'] === 'high') {
                    $suggestions['best_times'][] = "🌊 High tide at {$tide['time']} — fish 2 hours either side for best results.";
                    break;
                }
            }
        }

        $suggestions['best_times'][] = "🌇 Evening session: Last hour before {$sunset} can produce great catches.";

        $rainChance = $weather['summary']['rain_chance'] ?? 30;
        $windSpeed = $weather['summary']['wind_speed_mph'] ?? 10;
        $temp = $weather['summary']['temp_high'] ?? 15;

        $suggestions['clothing'] = [];
        if ($temp < 8) {
            $suggestions['clothing'][] = '🧥 Thermal base layers and warm fleece';
            $suggestions['clothing'][] = '🧤 Insulated gloves (fingerless for rigging)';
            $suggestions['clothing'][] = '🎩 Warm hat and neck gaiter';
        } elseif ($temp < 15) {
            $suggestions['clothing'][] = '🧥 Layered clothing — mornings will be cool';
            $suggestions['clothing'][] = '🧤 Light gloves for early morning';
        } else {
            $suggestions['clothing'][] = '👕 Light layers — it\'ll be warm';
            $suggestions['clothing'][] = '🧴 Sun cream (SPF 30+)';
            $suggestions['clothing'][] = '🧢 Sun hat or cap';
        }

        if ($rainChance > 40) {
            $suggestions['clothing'][] = '🌧️ Waterproof jacket and trousers — rain is likely';
        }

        $suggestions['clothing'][] = '👢 Wellies or waterproof boots';

        $suggestions['general_tips'] = [];
        if ($windSpeed > 15) {
            $suggestions['general_tips'][] = '💨 Windy conditions — use heavier weights and fish sheltered banks.';
        }
        if ($rainChance > 50) {
            $suggestions['general_tips'][] = '🐟 Overcast/rainy conditions often mean better fishing — fish feed more confidently.';
        }
        $suggestions['general_tips'][] = '📱 Tell someone where you\'re going and when you\'ll be back.';
        $suggestions['general_tips'][] = '🗑️ Leave no trace — take all litter home.';

        if (!empty($species['species'])) {
            $topSpecies = array_slice($species['species'], 0, 3);
            $suggestions['target_species'] = array_map(fn($s) => [
                'name' => $s['name'],
                'rating' => $s['rating'],
                'top_bait' => $s['recommended_baits'][0] ?? 'Worms',
                'tip' => $s['tips'],
            ], $topSpecies);
        }

        return $suggestions;
    }

    private function generateChecklist(Hunt $hunt, array $weather, ?array $tides, array $species, array $suggestions): void
    {
        $items = [];
        $order = 0;

        // Essential items
        $essentials = [
            'Rod licence (if 13+)' => 'Required by law for freshwater fishing in England & Wales',
            'Landing net' => null,
            'Unhooking mat' => 'Protect the fish!',
            'Tackle box' => null,
            'Bait' => null,
            'Spare hooks & line' => null,
            'Scissors / line cutters' => null,
            'Disgorger or forceps' => 'For safe hook removal',
        ];

        foreach ($essentials as $label => $notes) {
            $items[] = [
                'hunt_id' => $hunt->id,
                'category' => 'Essentials',
                'label' => $label,
                'notes' => $notes,
                'sort_order' => $order++,
            ];
        }

        // Species-specific tackle
        if (!empty($species['species'])) {
            foreach (array_slice($species['species'], 0, 2) as $sp) {
                foreach (array_slice($sp['recommended_tackle'], 0, 3) as $tackle) {
                    $items[] = [
                        'hunt_id' => $hunt->id,
                        'category' => "Tackle ({$sp['name']})",
                        'label' => $tackle,
                        'notes' => null,
                        'sort_order' => $order++,
                    ];
                }
                foreach (array_slice($sp['recommended_baits'], 0, 2) as $bait) {
                    $items[] = [
                        'hunt_id' => $hunt->id,
                        'category' => "Bait ({$sp['name']})",
                        'label' => $bait,
                        'notes' => null,
                        'sort_order' => $order++,
                    ];
                }
            }
        }

        // Clothing from suggestions
        if (!empty($suggestions['clothing'])) {
            foreach ($suggestions['clothing'] as $item) {
                $items[] = [
                    'hunt_id' => $hunt->id,
                    'category' => 'Clothing',
                    'label' => preg_replace('/^[^\w]+/', '', $item),
                    'notes' => null,
                    'sort_order' => $order++,
                ];
            }
        }

        // Food & drink
        $foodItems = ['Water bottle', 'Snacks / sandwiches', 'Hot flask (tea/coffee)'];
        foreach ($foodItems as $food) {
            $items[] = [
                'hunt_id' => $hunt->id,
                'category' => 'Food & Drink',
                'label' => $food,
                'notes' => null,
                'sort_order' => $order++,
            ];
        }

        // Safety
        $safetyItems = ['Phone (fully charged)', 'First aid kit', 'Torch / headlamp'];
        if ($hunt->is_coastal) {
            $safetyItems[] = 'Life jacket / buoyancy aid';
            $safetyItems[] = 'Tide timetable (printed backup)';
        }
        foreach ($safetyItems as $safety) {
            $items[] = [
                'hunt_id' => $hunt->id,
                'category' => 'Safety',
                'label' => $safety,
                'notes' => null,
                'sort_order' => $order++,
            ];
        }

        // Comfort
        $comfortItems = ['Folding chair / seat box', 'Umbrella / bivvy'];
        foreach ($comfortItems as $comfort) {
            $items[] = [
                'hunt_id' => $hunt->id,
                'category' => 'Comfort',
                'label' => $comfort,
                'notes' => null,
                'sort_order' => $order++,
            ];
        }

        foreach ($items as $item) {
            HuntChecklistItem::create($item);
        }
    }
}
