<boltAction type="file" filePath="app/Http/Controllers/PostController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\Post;
use App\Models\PostImage;
use App\Services\BadgeService;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Auth;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Storage;
use Intervention\Image\ImageManager;

class PostController extends Controller
{
    public function show(Post $post)
    {
        $this->authorize('view', $post);

        $post->load(['user', 'images', 'comments.user', 'comments.replies.user', 'likes']);
        $post->loadCount(['likes', 'allComments']);

        return view('posts.show', compact('post'));
    }

    public function create()
    {
        $this->authorize('create', Post::class);
        return view('posts.create');
    }

    public function store(Request $request, BadgeService $badgeService)
    {
        $this->authorize('create', Post::class);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:5000',
            'location_name' => 'nullable|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'location_privacy' => 'required|in:exact,approximate',
            'species' => 'nullable|string|max:255',
            'bait_used' => 'nullable|string|max:255',
            'gear_notes' => 'nullable|string|max:2000',
            'caught_at' => 'nullable|date|before_or_equal:now',
            'images' => 'required|array|min:1|max:5',
            'images.*' => 'image|mimes:jpeg,jpg,png,webp|max:10240',
        ]);

        $post = DB::transaction(function () use ($validated, $request) {
            $post = Auth::user()->posts()->create([
                'title' => $validated['title'],
                'description' => $validated['description'] ?? null,
                'location_name' => $validated['location_name'] ?? null,
                'latitude' => $validated['latitude'] ?? null,
                'longitude' => $validated['longitude'] ?? null,
                'location_privacy' => $validated['location_privacy'],
                'species' => $validated['species'] ?? null,
                'bait_used' => $validated['bait_used'] ?? null,
                'gear_notes' => $validated['gear_notes'] ?? null,
                'caught_at' => $validated['caught_at'] ?? now(),
            ]);

            if ($request->hasFile('images')) {
                foreach ($request->file('images') as $index => $image) {
                    $path = $image->store('posts/' . $post->id, 'public');

                    // Generate thumbnail
                    $thumbPath = 'posts/' . $post->id . '/thumb_' . $image->hashName();
                    $thumbFullPath = Storage::disk('public')->path($thumbPath);

                    // Simple thumbnail - copy original (GD thumbnail generation)
                    $this->createThumbnail(
                        $image->getRealPath(),
                        $thumbFullPath,
                        400,
                        300
                    );

                    PostImage::create([
                        'post_id' => $post->id,
                        'path' => $path,
                        'thumbnail_path' => $thumbPath,
                        'original_name' => $image->getClientOriginalName(),
                        'size' => $image->getSize(),
                        'mime_type' => $image->getMimeType(),
                        'sort_order' => $index,
                    ]);
                }
            }

            return $post;
        });

        $badgeService->checkAndAwardBadges(Auth::user());

        return redirect()->route('posts.show', $post)
            ->with('success', 'Catch posted! 🎣');
    }

    public function edit(Post $post)
    {
        $this->authorize('update', $post);
        $post->load('images');
        return view('posts.edit', compact('post'));
    }

    public function update(Request $request, Post $post)
    {
        $this->authorize('update', $post);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'description' => 'nullable|string|max:5000',
            'location_name' => 'nullable|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'location_privacy' => 'required|in:exact,approximate',
            'species' => 'nullable|string|max:255',
            'bait_used' => 'nullable|string|max:255',
            'gear_notes' => 'nullable|string|max:2000',
            'caught_at' => 'nullable|date|before_or_equal:now',
            'new_images' => 'nullable|array|max:5',
            'new_images.*' => 'image|mimes:jpeg,jpg,png,webp|max:10240',
        ]);

        $post->update($validated);

        if ($request->hasFile('new_images')) {
            $currentCount = $post->images()->count();
            foreach ($request->file('new_images') as $index => $image) {
                if ($currentCount + $index >= 5) break;

                $path = $image->store('posts/' . $post->id, 'public');
                $thumbPath = 'posts/' . $post->id . '/thumb_' . $image->hashName();
                $this->createThumbnail(
                    $image->getRealPath(),
                    Storage::disk('public')->path($thumbPath),
                    400, 300
                );

                PostImage::create([
                    'post_id' => $post->id,
                    'path' => $path,
                    'thumbnail_path' => $thumbPath,
                    'original_name' => $image->getClientOriginalName(),
                    'size' => $image->getSize(),
                    'mime_type' => $image->getMimeType(),
                    'sort_order' => $currentCount + $index,
                ]);
            }
        }

        return redirect()->route('posts.show', $post)
            ->with('success', 'Post updated!');
    }

    public function destroy(Post $post)
    {
        $this->authorize('delete', $post);

        foreach ($post->images as $image) {
            Storage::disk('public')->delete($image->path);
            if ($image->thumbnail_path) {
                Storage::disk('public')->delete($image->thumbnail_path);
            }
        }

        $post->delete();

        return redirect()->route('feed')
            ->with('success', 'Post deleted.');
    }

    public function toggleHide(Post $post)
    {
        $this->authorize('hide', $post);

        $post->update(['is_hidden' => !$post->is_hidden]);

        return back()->with('success', $post->is_hidden ? 'Post hidden.' : 'Post unhidden.');
    }

    private function createThumbnail(string $sourcePath, string $destPath, int $width, int $height): void
    {
        $dir = dirname($destPath);
        if (!is_dir($dir)) {
            mkdir($dir, 0755, true);
        }

        $info = getimagesize($sourcePath);
        if (!$info) {
            copy($sourcePath, $destPath);
            return;
        }

        $mime = $info['mime'];
        $source = match ($mime) {
            'image/jpeg' => imagecreatefromjpeg($sourcePath),
            'image/png' => imagecreatefrompng($sourcePath),
            'image/webp' => imagecreatefromwebp($sourcePath),
            default => null,
        };

        if (!$source) {
            copy($sourcePath, $destPath);
            return;
        }

        $origW = imagesx($source);
        $origH = imagesy($source);

        $ratio = min($width / $origW, $height / $origH);
        $newW = (int) ($origW * $ratio);
        $newH = (int) ($origH * $ratio);

        $thumb = imagecreatetruecolor($newW, $newH);

        if ($mime === 'image/png' || $mime === 'image/webp') {
            imagealphablending($thumb, false);
            imagesavealpha($thumb, true);
        }

        imagecopyresampled($thumb, $source, 0, 0, 0, 0, $newW, $newH, $origW, $origH);

        match ($mime) {
            'image/jpeg' => imagejpeg($thumb, $destPath, 80),
            'image/png' => imagepng($thumb, $destPath, 8),
            'image/webp' => imagewebp($thumb, $destPath, 80),
            default => imagejpeg($thumb, $destPath, 80),
        };

        imagedestroy($source);
        imagedestroy($thumb);
    }
}
