<?php

namespace App\Services;

use App\Models\Badge;
use App\Models\User;

class BadgeService
{
    public function checkAndAwardBadges(User $user): array
    {
        $awarded = [];
        $user->load('posts', 'hunts', 'badges');

        $checks = [
            'first-catch' => fn() => $user->posts()->count() >= 1,
            'five-catches' => fn() => $user->posts()->count() >= 5,
            'ten-catches' => fn() => $user->posts()->count() >= 10,
            'three-species' => fn() => $user->getUniqueSpeciesCount() >= 3,
            'five-species' => fn() => $user->getUniqueSpeciesCount() >= 5,
            'first-hunt' => fn() => $user->hunts()->count() >= 1,
            'five-hunts' => fn() => $user->hunts()->count() >= 5,
            'social-angler' => fn() => $user->comments()->count() >= 10,
            'popular-catch' => fn() => $user->posts()->withCount('likes')->get()->max('likes_count') >= 5,
        ];

        foreach ($checks as $slug => $check) {
            if ($user->badges->contains('slug', $slug)) continue;

            if ($check()) {
                $badge = Badge::where('slug', $slug)->first();
                if ($badge) {
                    $user->badges()->attach($badge->id, ['earned_at' => now()]);
                    $awarded[] = $badge;
                }
            }
        }

        return $awarded;
    }
}
