            'user_id' => Auth::id(),
            'body' => $validated['body'],
            'parent_id' => $validated['parent_id'] ?? null,
        ]);

        $badgeService->checkAndAwardBadges(Auth::user());

        return back()->with('success', 'Comment added!');
    }

    public function destroy(Comment $comment)
    {
        $this->authorize('delete', $comment);
        $comment->delete();
        return back()->with('success', 'Comment removed.');
    }

    public function toggleHide(Comment $comment)
    {
        $this->authorize('hide', $comment);
        $comment->update(['is_hidden' => !$comment->is_hidden]);
        return back()->with('success', $comment->is_hidden ? 'Comment hidden.' : 'Comment unhidden.');
